import { isNullOrUndefinedOrEmpty } from './null-checks.js'

/**
 * Determina si se debe omitir una consulta basándose en el tiempo transcurrido
 * @param {string|Date|null} ultimaConsulta - Timestamp de la última consulta
 * @param {number} intervalo - Milisegundos mínimos entre consultas
 * @returns {boolean} - true si se debe omitir la consulta
 */
export const omitirConsulta = (ultimaConsulta, intervalo) => {
  if (isNullOrUndefinedOrEmpty(ultimaConsulta)) return false
  const now = new Date()
  const prev = new Date(ultimaConsulta)
  return now.getTime() - prev.getTime() < intervalo
}
